# ═══════════════════════════════════════════════════════
# MULTI-AGENT SPAWN
# ═══════════════════════════════════════════════════════
def _dispatch_spawn_agents(args):
    """Spawn sub-agents untuk task independen, jalan paralel."""
    import concurrent.futures

    subtasks = args.get("subtasks", [])
    if not subtasks or len(subtasks) < 2:
        return "[error] butuh minimal 2 subtasks untuk multi-agent"
    if len(subtasks) > 6:
        return "[error] maksimal 6 subagents (resource limit)"

    results = [None] * len(subtasks)

    def _run_subtask(idx_task):
        idx, task_desc = idx_task
        try:
            import agent as agent_mod
            sub = agent_mod.Agent(
                provider_name=None,  # use default
                mode="auto",         # no confirm needed
                notify=lambda msg: None,  # silent
                auto_trim_ratio=0.5,  # aggressive trim, sub-agent context kecil
            )
            sub.reset()
            sub.chat(task_desc, max_iters=8)
            # Ambil last assistant message sebagai result
            for msg in reversed(sub.messages):
                if msg.get("role") == "assistant" and msg.get("content"):
                    return idx, msg["content"]
            return idx, "(no output from sub-agent)"
        except Exception as e:
            return idx, f"[error] sub-agent {idx+1}: {e}"

    with concurrent.futures.ThreadPoolExecutor(max_workers=min(4, len(subtasks))) as ex:
        futures = {ex.submit(_run_subtask, (i, t)): i for i, t in enumerate(subtasks)}
        for future in concurrent.futures.as_completed(futures):
            idx, result = future.result()
            results[idx] = result

    # Format output
    output_parts = []
    for i, r in enumerate(results):
        if r is None:
            r = "(no result)"
        output_parts.append(f"--- Sub-Agent {i+1} ---\n{r}")

    return "\n\n".join(output_parts)

